import puppeteer from 'puppeteer';

(async () => {
  const browser = await puppeteer.connect({ browserWSEndpoint: 'ws://localhost:9222/devtools/browser' });
  const page = (await browser.pages())[0];
  await page.goto('https://stackoverflow.com/questions/11227809/why-is-processing-a-sorted-array-faster-than-processing-an-unsorted-array');

  // Wait for the page to load
  await page.waitForSelector('.accepted-answer');

  // Vote count
  const voteCount = await page.evaluate(() => {
    const el = document.querySelector('.accepted-answer .js-vote-count');
    return el ? el.textContent.trim() : null;
  });

  // Author
  const author = await page.evaluate(() => {
    const el = document.querySelector('.accepted-answer .user-details a');
    return el ? el.textContent.trim() : null;
  });

  // Code blocks
  const codeBlocks = await page.evaluate(() => {
    return document.querySelectorAll('.accepted-answer pre').length;
  });

  // Total answers
  const totalAnswers = await page.evaluate(() => {
    const el = document.querySelector('#answers h2');
    if (el) {
      const match = el.textContent.match(/(\d+)/);
      return match ? match[1] : null;
    }
    return null;
  });

  // Screenshot of accepted answer
  const acceptedAnswer = await page.$('.accepted-answer');
  await acceptedAnswer.screenshot({ path: 'eval-so-audit.png' });

  console.log(`AcceptedAnswerVotes:${voteCount}`);
  console.log(`AcceptedAnswerAuthor:${author}`);
  console.log(`CodeBlockCount:${codeBlocks}`);
  console.log(`TotalAnswers:${totalAnswers}`);

  await browser.disconnect();
})();

